import './pages/styles/MainStyles.css'
import { useState } from 'react';
import { FormSignInSignUp } from './pages/FormSignInSignUp/FormSignInSignUp';
import {} from './components/Load'


function App() {
  // let component
  // switch(window.location.pathname){
  //   case "/":
  //     component = <SignIn/>
  //     break
  //   case "/registr":
  //     component = <SignUp/>
  //     break
  // }

  const [showForm, setShow] = useState(false)

  return (
    <>
    <header>
        <div class="container">
            <div class="logo">
                <img src="../materials/logo.png" alt="Paw Pals Logo"/>
                <span>PawPals</span>
            </div>
            <nav>
                <a href="" class="active">Главная</a>
                <a href="">Найти питомца</a>
                <a href="">Ваши питомцы</a>
                <a href="">Встречи</a>
                <a class="no-underline"> <button onClick={(e) => { setShow(true) }}> Войти</button></a>
            </nav>
        </div>
    </header>

    <Load/>

    {showForm && (
        <div className="modal-overlay" onClick={(e) => {
          // Закрываем только если кликнули именно на оверлей
          if (e.target === e.currentTarget) {
            setShow(false);
          }}}>
          (<FormSignInSignUp setShow = {setShow}/>)
        </div>
      )}
    </>
  );
}

export default App;
